using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ---------------------------------------------------------------------------
// Chat client (MEAI abstraction over OpenAI provider)
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ---------------------------------------------------------------------------
// Shared state for the note-taking tool
// ---------------------------------------------------------------------------
var notes = new List<ResearchNote>();

using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0 (.NET 10)");
httpClient.Timeout = TimeSpan.FromSeconds(15);

// ---------------------------------------------------------------------------
// AI tool definitions
// ---------------------------------------------------------------------------
var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWeb, "search_web",
        "Search the web for information. Returns result snippets and URLs."),

    AIFunctionFactory.Create(FetchPage, "fetch_page",
        "Fetch a web page URL and return its text content (max 4 000 chars)."),

    AIFunctionFactory.Create(SaveNote, "save_note",
        "Save a research note with a title and detailed content for later reference."),

    AIFunctionFactory.Create(GetNotes, "get_notes",
        "Retrieve all previously saved research notes."),
};

// ---------------------------------------------------------------------------
// Create the research agent (Microsoft Agent Framework)
// ---------------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. When given a topic:
        1. Use search_web with several varied queries to find information.
        2. Use fetch_page to read the most promising URLs for details.
        3. Use save_note to record each key finding as you go.
        4. After gathering enough information (at least 3 sources),
           use get_notes to review everything you collected.
        5. Produce a well-structured final summary with:
           - An overview paragraph
           - Key findings as bullet points
           - Sources cited with URLs
        Be thorough but concise. Always cite your sources.
        """,
    name: "ResearchAgent",
    description: "Researches a topic via web search and note-taking, then summarizes findings.",
    tools: tools);

// ---------------------------------------------------------------------------
// Prompt the user for a topic
// ---------------------------------------------------------------------------
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}");
Console.WriteLine(new string('─', 60));

// ---------------------------------------------------------------------------
// Run the agent with streaming output
// ---------------------------------------------------------------------------
var session = await agent.CreateSessionAsync("research");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine("✅ Research complete.");

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------
async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    Console.WriteLine($"  🌐 Searching: {query}");

    var encoded = WebUtility.UrlEncode(query);
    var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

    string json;
    try
    {
        json = await httpClient.GetStringAsync(url);
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }

    using var doc = JsonDocument.Parse(json);
    var root = doc.RootElement;

    var sb = new StringBuilder();

    // Instant-answer abstract
    var abs = root.GetProperty("AbstractText").GetString();
    if (!string.IsNullOrWhiteSpace(abs))
    {
        sb.AppendLine($"Summary: {abs}");
        sb.AppendLine($"Source: {root.GetProperty("AbstractURL").GetString()}");
        sb.AppendLine();
    }

    // Related topics
    if (root.TryGetProperty("RelatedTopics", out var topics))
    {
        var count = 0;
        foreach (var item in topics.EnumerateArray())
        {
            if (count >= 8) break;
            var text = item.TryGetProperty("Text", out var tv) ? tv.GetString() : null;
            var link = item.TryGetProperty("FirstURL", out var uv) ? uv.GetString() : null;
            if (!string.IsNullOrWhiteSpace(text))
            {
                sb.AppendLine($"- {text}");
                if (!string.IsNullOrWhiteSpace(link))
                    sb.AppendLine($"  URL: {link}");
                count++;
            }
        }
    }

    return sb.Length > 0 ? sb.ToString() : "No results found. Try a different search query.";
}

async Task<string> FetchPage(
    [Description("The full URL to fetch")] string url)
{
    Console.WriteLine($"  📄 Fetching: {url}");
    try
    {
        var html = await httpClient.GetStringAsync(url);

        // Strip scripts, styles, and HTML tags for a rough text extraction
        var text = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ",
            RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<style[^>]*>[\s\S]*?</style>", " ",
            RegexOptions.IgnoreCase);
        text = Regex.Replace(text, "<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"\s+", " ").Trim();

        return text.Length > 4_000 ? text[..4_000] + "…" : text;
    }
    catch (Exception ex)
    {
        return $"Error fetching page: {ex.Message}";
    }
}

string SaveNote(
    [Description("Short title for the note")] string title,
    [Description("Detailed content of the note")] string content)
{
    Console.WriteLine($"  📝 Saving note: {title}");
    notes.Add(new ResearchNote(title, content));
    return $"Note saved: \"{title}\" ({notes.Count} total notes).";
}

string GetNotes()
{
    Console.WriteLine("  📋 Retrieving all notes…");
    if (notes.Count == 0) return "No notes saved yet.";

    var sb = new StringBuilder();
    for (var i = 0; i < notes.Count; i++)
    {
        sb.AppendLine($"[{i + 1}] {notes[i].Title}");
        sb.AppendLine(notes[i].Content);
        sb.AppendLine();
    }

    return sb.ToString();
}

// ---------------------------------------------------------------------------
// Supporting types
// ---------------------------------------------------------------------------
record ResearchNote(string Title, string Content);

